import type { PublicKey } from "../../crypto";
import { serializeBorsh } from "../../serialization";
import type { AccountMeta, Instruction } from "../types";

/**
 * Create an instruction with Borsh-encoded data.
 *
 * @example
 * ```typescript
 * // Define your instruction data class
 * class MyInstructionData {
 *   @field({ type: 'u8' })
 *   instruction: number;
 *
 *   @field({ type: 'u64' })
 *   amount: bigint;
 *
 *   @field({ type: option('string') })
 *   memo?: string;
 * }
 *
 * // Create instruction
 * const instruction = createBorshInstruction({
 *   programId: myProgramId,
 *   accounts: [
 *     { pubkey: account1, isSigner: true, isWritable: true },
 *     { pubkey: account2, isSigner: false, isWritable: false },
 *   ],
 *   data: new MyInstructionData({
 *     instruction: 5,
 *     amount: 1000n,
 *     memo: "Hello, Rialo!",
 *   }),
 * });
 * ```
 */
export function createBorshInstruction<T>(params: {
	programId: PublicKey;
	accounts: AccountMeta[];
	data: T;
}): Instruction {
	return {
		programId: params.programId,
		accounts: params.accounts,
		data: serializeBorsh(params.data),
	};
}

